import React, { useState } from 'react';
import swe1 from '../assets/swe1.jpg';
import swe2 from '../assets/swe2.jpg';
import swe3 from '../assets/swe3.jpg';
import dsc1 from '../assets/dsc1.jpg';
import dsc2 from '../assets/dsc2.jpg';
import dsc3 from '../assets/dsc3.jpg';
import spartan from '../assets/spartan.jpg';
import spartan2 from '../assets/spartan2.jpg';
import img4361 from '../assets/img4361.jpg';
import img4362 from '../assets/img4362.jpg';
import img4363 from '../assets/img4363.jpg';
import './Involvement.css';

const orgs = [
  {
    id: 'rcc',
    label: 'Responsible Computing Club',
    roles: [
      'Mozilla & Firefox Ambassador',
      'Vice President of External Affairs',
      'Community Engagement Lead Ambassador',
    ],
    photos: [dsc1, dsc2, dsc3],
  },
  {
    id: 'swe',
    label: 'Society of Women Engineers',
    roles: [
      'Alumni Relations Committee Chair',
      'Mentorship Committee Chair',
      'SWE++ Program Volunteer',
    ],
    photos: [swe1, swe2, swe3],
  },
  {
    id: 'capise',
    label: 'CAPISE',
    roles: ['Asian Pacific Islander EM Empower Mentor'],
    photos: [img4361, img4362, img4363],
  },
  {
    id: 'spartan',
    label: 'Spartan Racing Formula SAE',
    roles: ['Business Team Intern'],
    photos: [spartan, spartan2],
  },
];

export default function Involvement() {
  const [activeId, setActiveId] = useState('rcc');
  const activeOrg = orgs.find((o) => o.id === activeId);

  return (
    <section id="involvement" className="involvement-section">
      <div className="inner">
        <span className="section-label reveal">On Campus</span>
        <h2 className="section-title reveal d1">Involvement</h2>



        {/* Photo grid */}
        {activeOrg && (
          <div
            className={`inv-grid ${activeOrg.photos.length === 2 ? 'grid-2' : 'grid-3'}`}
            key={activeId}
          >
            {activeOrg.photos.length === 0 && (
              <div className="inv-empty">
                Photos coming soon!
              </div>
            )}
            {activeOrg.photos.map((photo, i) => (
              <div className="inv-card" key={i}>
                <img src={photo} alt={`${activeOrg.label} ${i + 1}`} />
                <div className="inv-overlay">
                  <div className="inv-org-name">{activeOrg.label}</div>
                  <div className="inv-divider" />
                  <div className="inv-roles">
                    {activeOrg.roles.map((r) => (
                      <span key={r} className="inv-role">{r}</span>
                    ))}
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
}
